rule comparison_op() -> CompareOperator
    = "eq" { CompareOperator::Equal }
    / "ne" { CompareOperator::NotEqual }
    / "gt" { CompareOperator::GreaterThan }
    / "ge" { CompareOperator::GreaterOrEqual }
